import java.io.*;
import java.util.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String name = scanner.nextLine();

        // Escape user input to prevent XSS
        String escapedName = StringEscapeUtils.escapeHtml4(name);

        System.out.println("Hello, " + escapedName + "!"); // Escaped output to prevent XSS

        // Properly handle user input to avoid XSS
        System.out.println("<script>alert('XSS Vulnerability')</script>"); // This will be displayed as text and not executed as a script
    }
}

